#include <stdio.h>
#include <string.h>

struct Month {
    char name[10];
    int value;
};

int main() {
    struct Month dict[] = {
        {"January", 0},
        {"February", 1},
        {"March", 2},
        {"April", 3},
        {"May", 4},
        {"June", 5},
        {"July", 6},
        {"August", 7},
        {"September", 8},
        {"October", 9},
        {"November", 10},
        {"December", 11}
    };
    char tmp[10];
    int s;
    scanf("%s", tmp);
    scanf("%d", &s);
    for (int i = 0; i < 12; i++) {
        if (strcmp(dict[i].name, tmp) == 0) {
            s += dict[i].value;
            break;
        }
    }
    s %= 12;
    for (int i = 0; i < 12; i++) {
        if (dict[i].value == s) {
            printf("%s\n", dict[i].name);
            break;
        }
    }
    return 0;
}
